eaip:TransportLayer.eaip:ProtoStandards:
syntax = "proto3";
package eaip.v1;
import "eaip/v1/rce_envelope.proto";
message SubmitTaskRequest {
  RCEEnvelope context = 1;  // MUST always be field 1
  string task_id = 2;
  bytes payload = 3;
}

eaip:TransportLayer.eaip:DeadlinePropagation:
// All outbound gRPC calls MUST propagate the remaining deadline from the inbound context.
func PropagateDeadline(ctx context.Context) (context.Context, context.CancelFunc) {
    if deadline, ok := ctx.Deadline(); ok {
        return context.WithDeadline(context.Background(), deadline)
    }
    return context.WithTimeout(context.Background(), 30*time.Second)
}

eaip:StateManagement.eaip:EnvelopeSchema:
message RCEEnvelope {
  string trace_id = 1;
  string root_span_id = 2;
  string session_id = 3;
  repeated ContextFrame frames = 5;
  google.protobuf.Struct session_state = 6;
  int32 schema_version = 8; // MUST be 3
}
